
import {
    mathCos as cos, mathSin as sin, mathPow as pow, mathAtan2 as atan2, mathAtan as atan,
    mathPI as PI, mathSQRT as sqrt
} from "../../core/zc-constants";

const square = x => pow(x, 2),
    cube = x => pow(x, 3),
    mul = function () {
        return [...arguments].reduce((prev = 1, curr) => prev * curr);
    };

const midpoint = (a, b) => (a - b) / 2, 
    average = (a, b) => (a + b) / 2,
    slope = (x1, y1, x2, y2) => (y2 - y1) / (x2 - x1);

export const EQUATIONS = {
    linear_bezier_curve: (p0, p1) => t => mul(1 - t, p0) + mul(t, p1),  //* 0 <= t <= 1
    quadratic_bezier_curve: (p0, p1, p2) => t => mul(square(1 - t), p0) + mul(2, 1 - t, t, p1) + mul(t, p2),
    cubic_bezier_curve: (p0, p1, p2, p3) => t => mul(cube(1 - t), p0) + mul(3, square(1 - t), t, p1) + mul(3, 1 - t, square(t), p2) + mul(cube(t), p3),
    angle_between_two_lines: (m1, m2) => mul(m1, m2) == -1 ? PI / 2 : atan((m2 - m1) / (1 + m1 * m2)),
    midpoint, average, slope
}